3	export function quote(input: { items: unknown[]; years: number; priorContract: boolean }): { premium: number } {
4	  if (input.items.length === 0) return { premium: PROCESSING_FEE };
5	  return { premium: 115 };
6	}
7	
8	export function claim(_input: unknown): unknown {
9	  return undefined;
10	}
